   305→// TestRewind_MultipleNewFiles tests that sessions creating multiple files work correctly.
   306→// All strategies use a single session with multiple checkpoints.
   307→func TestRewind_MultipleNewFiles(t *testing.T) {
   308→	t.Parallel()
   309→	RunForAllStrategies(t, func(t *testing.T, env *TestEnv, strategyName string) {
   310→		// Add .gitignore to the repo
   311→		env.WriteFile(".gitignore", ".entire/\n")
   312→		env.GitAdd(".gitignore")
   313→		env.GitCommit("Add gitignore")
   314→
   315→		// Use same session for all checkpoints (works for all strategies)
   316→		session := env.NewSession()
   317→
   318→		// Checkpoint 1: creating multiple files in different directories
   319→		if err := env.SimulateUserPromptSubmit(session.ID); err != nil {
