}

// PreUntrackedFiles returns the untracked files list, or nil if the receiver is nil.
// See PrePromptState.PreUntrackedFiles for nil-vs-empty semantics.
func (s *PreTaskState) PreUntrackedFiles() []string {
	if s == nil {
		return nil
	}
