	env.WriteFile("fileA.go", "package main\n\n// Manual edit by user\nfunc A() { return }\n")

	// Commit the manual edit - should NOT get checkpoint
	env.GitCommitWithShadowHooks("Manual edit to file A", "fileA.go")
